#include<bits/stdc++.h>
using namespace std;
long long a[300010],b[300010],sum[300010],blksiz,blk[300010],blkl[300010],blkr[300010],tag[300010];
void pushadd(long long x,long long v)
{
    tag[x]+=v;
    sum[x]+=(blkr[x]-blkl[x]+1)*v;
}
void pushdown(long long x)
{
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        a[i]+=tag[x];
        b[i]+=tag[x];
    }
    tag[x]=0;
}
void sortblk(long long x)
{
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        b[i]=a[i];
    }
    sort(b+blkl[x],b+1+blkr[x]);
}
void add(long long l,long long r,long long v)
{
    if(blk[l]==blk[r])
    {
        pushdown(blk[l]);
        for(long long i=l;i<=r;i++)
        {
            a[i]+=v;
        }
        sortblk(blk[l]);
        return;
    }
    pushdown(blk[l]);
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        a[i]+=v;
    }
    sortblk(blk[l]);
    pushdown(blk[r]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        a[i]+=v;
    }
    sortblk(blk[r]);
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        pushadd(i,v);
    }
}
long long query(long long l,long long r,long long val)
{
    long long ans=0;
    if(blk[l]==blk[r])
    {
        pushdown(blk[l]);
        for(long long i=l;i<=r;i++)
        {
            if(a[i]<=val)
            {
                ans++;
            }
        }
        return ans;
    }
    pushdown(blk[l]);
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        if(a[i]<=val)
        {
            ans++;
        }
    }
    pushdown(blk[r]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        if(a[i]<=val)
        {
            ans++;
        }
    }
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        ans+=upper_bound(b+blkl[i],b+1+blkr[i],val-tag[i])-b-blkl[i];
    }
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i];
        blk[i]=(i+blksiz-1)/blksiz;
        sum[blk[i]]+=a[i];
    }
    for(long long i=1;blksiz*(i-1)+1<=n;i++)
    {
        blkl[i]=blksiz*(i-1)+1;
        blkr[i]=min(n,blksiz*i);
        sortblk(i);
    }
    while(n--)
    {
        long long op,l,r,c;
        scanf("%lld%lld%lld%lld",&op,&l,&r,&c);
        if(op==0)
        {
            add(l,r,c);
        }
        else
        {
            printf("%lld\n",query(l,r,c*c-1));
        }
    }
    return 0;
}
